# Build a semantic map of a file using semantic tokens
async def summarise_file_symbols(lsp, file_path: str, server_caps: dict) -> str:
    tokens = await get_semantic_tokens_for_file(lsp, file_path, server_caps)
    source_lines = Path(file_path).read_text().splitlines()

    # Group tokens by type
    by_type: dict[str, list[str]] = {}
    for tok in tokens:
        if tok.token_type in {"class", "function", "method", "namespace"}:
            line_text = source_lines[tok.line] if tok.line < len(source_lines) else ""
            name = line_text[tok.character:tok.character + tok.length]
            by_type.setdefault(tok.token_type, []).append(f"L{tok.line}: {name}")

    lines = [f"Semantic summary of {file_path}:"]
    for kind, names in sorted(by_type.items()):
        lines.append(f"  {kind}: {', '.join(names[:10])}")
    return "\n".join(lines)
